def log_calls(func):
    def wrapper(*args, **kwargs):
        print(f'→ Виклик {func.__name__}({args}, {kwargs})')
        result = func(*args, **kwargs)
        print(f'← Результат: {result}')
        return result
    return wrapper

@log_calls
def add(a, b):
    return a + b

@log_calls
def multiply(a, b):
    return a * b

add(2, 3)
multiply(4, 5)
